 11→MetatomicPotential::MetatomicPotential(const Parameters &params)
 12→    : Potential(PotType::METATOMIC, params),
 13→      model_(torch::jit::Module()),
 14→      device_type_(c10::DeviceType::CPU),
 15→      device_(torch::Device(device_type_)) {
 16→
 17→  m_log->info("[MetatomicPotential] Initializing...");
 18→
 19→  // Resolve variants
 20→  this->energy_key_ = "energy";
 21→  this->energy_uncertainty_key_ = "energy_uncertainty";
 22→
 23→  // Apply global variant if present
 24→  if (!m_metatomic_params.metatomic_options.variant.base.empty()) {
 25→    auto variant = m_metatomic_params.metatomic_options.variant.base;
 26→    this->energy_key_ += "/" + variant;
 27→    this->energy_uncertainty_key_ += "/" + variant;
 28→  }
 29→
 30→  // Apply variant/energy override
 31→  if (!m_metatomic_params.metatomic_options.variant.energy.empty()) {
 32→    if (m_metatomic_params.metatomic_options.variant.energy == "off") {
 33→      this->energy_key_ = "energy";
 34→    } else {
 35→      this->energy_key_ =
 36→          "energy/" + m_metatomic_params.metatomic_options.variant.energy;
 37→    }
 38→  }
 39→
 40→  // Apply variant/energy_uncertainty override
 41→  if (!m_metatomic_params.metatomic_options.variant.energy_uncertainty
 42→           .empty()) {
 43→    if (m_metatomic_params.metatomic_options.variant.energy_uncertainty ==
 44→        "off") {
 45→      this->energy_uncertainty_key_ = "energy_uncertainty";
 46→    } else {
 47→      this->energy_uncertainty_key_ =
 48→          "energy_uncertainty/" +
 49→          m_metatomic_params.metatomic_options.variant.energy_uncertainty;
 50→    }
 51→  }
 52→
 53→  // 1. Load the model from the path specified in parameters
 54→  torch::optional<std::string> extensions_directory = torch::nullopt;
 55→  if (!m_metatomic_params.metatomic_options.extensions_directory.empty()) {
 56→    extensions_directory =
 57→        m_metatomic_params.metatomic_options.extensions_directory;
 58→  }
 59→
 60→  try {
 61→    m_log->info("[MetatomicPotential] Loading model from '{}'",
 62→                m_metatomic_params.metatomic_options.model_path);
 63→    this->model_ = metatomic_torch::load_atomistic_model(
 64→        m_metatomic_params.metatomic_options.model_path, extensions_directory);
 65→  } catch (const std::exception &e) {
 66→    m_log->error("[MetatomicPotential] Failed to load model: {}", e.what());
 67→    throw;
 68→  }
 69→
 70→  // 2. Extract capabilities and neighbor list requests from the model
 71→  this->capabilities_ =
 72→      this->model_.run_method("capabilities")
 73→          .toCustomClass<metatomic_torch::ModelCapabilitiesHolder>();
 74→  auto requests_ivalue = this->model_.run_method("requested_neighbor_lists");
 75→  for (const auto &request_ivalue : requests_ivalue.toList()) {
 76→    auto request =
 77→        request_ivalue.get()
 78→            .toCustomClass<metatomic_torch::NeighborListOptionsHolder>();
 79→    this->nl_requests_.push_back(request);
 80→  }
 81→
 82→  // 3. Determine and set up the device (CPU/CUDA/MPS)
 83→  // TODO(rg):: Eventually switch to upstream selection
 84→  // https://github.com/metatensor/metatomic/issues/21
 85→  torch::optional<std::string> desired = torch::nullopt;
 86→  if (!m_metatomic_params.metatomic_options.device.empty()) {
 87→    desired = m_metatomic_params.metatomic_options.device;
 88→  }
 89→  device_type_ = metatomic_torch::pick_device(
 90→      this->capabilities_->supported_devices, desired);
 91→
 92→  device_ = torch::Device(device_type_);
 93→  m_log->info("[MetatomicPotential] Using device: {}", device_.str());
 94→
 95→  this->model_.to(this->device_);
 96→
 97→  // 4. Set data type (float32/float64) based on model capabilities
 98→  if (this->capabilities_->dtype() == "float64") {
 99→    this->dtype_ = torch::kFloat64;
100→  } else if (this->capabilities_->dtype() == "float32") {
101→    this->dtype_ = torch::kFloat32;
102→  } else {
103→    throw std::runtime_error("Unsupported dtype: " +
104→                             this->capabilities_->dtype());
105→  }
106→  m_log->info("[MetatomicPotential] Using dtype: {}",
107→              this->capabilities_->dtype().c_str());
108→
109→  // 5. Set up evaluation options to request total energy
110→  this->evaluations_options_ =
111→      torch::make_intrusive<metatomic_torch::ModelEvaluationOptionsHolder>();
112→  evaluations_options_->set_length_unit(
113→      m_metatomic_params.metatomic_options.length_unit);
114→
115→  auto outputs = this->capabilities_->outputs();
116→  if (!outputs.contains(this->energy_key_)) {
117→    throw std::runtime_error("Metatomic model must provide an '" +
118→                             this->energy_key_ +
119→                             "' output to be used as a potential.");
120→  }
121→  auto energy_output_info = outputs.at(this->energy_key_);
122→
123→  auto requested_output =
124→      torch::make_intrusive<metatomic_torch::ModelOutputHolder>();
125→  requested_output->per_atom = false; // We want a single total energy value
126→  requested_output->explicit_gradients = {}; // Use autograd for forces
127→
128→  evaluations_options_->outputs.insert(this->energy_key_, requested_output);
129→
130→  // 5b. Optionally request energy uncertainty (per-atom) if the model offers it
131→  // and the user didn't disable it. We read a threshold from parameters to know
132→  // whether to warn (non-positive threshold disables checking).
133→  // Default: if user provided a positive threshold, use it; otherwise keep it
134→  // disabled (-1).
135→  if (m_metatomic_params.metatomic_options.uncertainty_threshold > 0) {
136→    this->uncertainty_threshold_ =
137→        m_metatomic_params.metatomic_options.uncertainty_threshold;
138→  } else {
139→    this->uncertainty_threshold_ = -1.0; // disabled
140→  }
141→
142→  auto uncertainty_it = outputs.find(this->energy_uncertainty_key_);
143→  if (uncertainty_it != outputs.end() && this->uncertainty_threshold_ > 0) {
144→    // If the model has per-atom uncertainty output, request it for evaluation.
145→    // Prefer only per-atom uncertainties for per-atom checking.
146→    try {
147→      // The capabilities entry may provide whether the output is per-atom.
148→      // We attempt to detect that; if not per-atom, we do not request it here.
149→      auto uncertainty_info = uncertainty_it->value();
150→      bool per_atom = false;
151→      try {
152→        per_atom = uncertainty_info->per_atom;
153→      } catch (...) {
154→        per_atom = false;
155→      }
156→
157→      if (per_atom) {
158→        auto requested_uncertainty =
159→            torch::make_intrusive<metatomic_torch::ModelOutputHolder>();
160→        requested_uncertainty->per_atom = true;
161→        requested_uncertainty->explicit_gradients = {};
162→        requested_uncertainty->set_quantity("energy");
163→        // leave unit unset or let metatomic handle unit conversion if available
164→        evaluations_options_->outputs.insert(this->energy_uncertainty_key_,
165→                                             requested_uncertainty);
166→        m_log->info("[MetatomicPotential] Requested per-atom "
167→                    "'{}' from model (threshold = {})",
168→                    this->energy_uncertainty_key_,
169→                    this->uncertainty_threshold_);
170→      } else {
171→        m_log->debug("[MetatomicPotential] Model provides '{}' "
172→                     "but not per-atom; skipping per-atom uncertainty checks.",
173→                     this->energy_uncertainty_key_);
174→      }
175→    } catch (...) {
176→      // If introspection fails, we skip requesting uncertainty
177→      m_log->debug("[MetatomicPotential] Could not determine "
178→                   "'{}' per-atom capability; skipping.",
179→                   this->energy_uncertainty_key_);
180→    }
181→  }
182→
183→  this->check_consistency_ =
184→      m_metatomic_params.metatomic_options.check_consistency;
185→  m_log->info("[MetatomicPotential] Initialization complete.");
186→}
187→
188→// --- MetatomicPotential::force ---
189→
190→void MetatomicPotential::force(long nAtoms, const double *positions,
191→                               const int *atomicNrs, double *forces,
192→                               double *energy, double *variance,
193→                               const double *box) {
194→  // 1. Convert input arrays to torch::Tensors
195→  auto f64_options =
196→      torch::TensorOptions().dtype(torch::kFloat64).device(torch::kCPU);
197→
198→  auto torch_positions = torch::from_blob(const_cast<double *>(positions),
199→                                          {nAtoms, 3}, f64_options)
200→                             .to(this->dtype_)
201→                             .to(this->device_)
202→                             .set_requires_grad(true);
203→
204→  auto torch_cell =
205→      torch::from_blob(const_cast<double *>(box), {3, 3}, f64_options)
206→          .to(this->dtype_)
207→          .to(this->device_);
208→
209→  auto cell_norms = torch::norm(torch_cell, 2, /*dim=*/1);
210→  auto torch_pbc = cell_norms.abs() > 1e-9;
211→  bool periodic = torch::all(torch_pbc).item<bool>();
212→
213→  bool types_changed = false;
214→  if (static_cast<size_t>(nAtoms) != last_atomic_nrs_.size()) {
215→    types_changed = true;
216→  } else if (nAtoms > 0 && std::memcmp(atomicNrs, last_atomic_nrs_.data(),
217→                                       nAtoms * sizeof(int)) != 0) {
218→    types_changed = true;
219→  }
220→
221→  if (types_changed) {
222→    m_log->trace("[MetatomicPotential] Atomic numbers changed, re-creating "
223→                 "types tensor.");
224→    if (!atomicNrs) {
225→      throw std::runtime_error(
226→          "[MetatomicPotential] `atomicNrs` must be provided.");
227→    }
228→    std::vector<int32_t> types_vec(atomicNrs, atomicNrs + nAtoms);
229→    // XXX(rg): Reordering of labels might take place for non-conservative
230→    // forces / per atom energies
231→    this->atomic_types_ =
232→        torch::tensor(types_vec, torch::TensorOptions().dtype(torch::kInt32))
233→            .to(this->device_);
234→
235→    // Update the cache
236→    last_atomic_nrs_.assign(atomicNrs, atomicNrs + nAtoms);
237→  }
238→
239→  // 2. Create the metatomic::System object
240→  auto system = torch::make_intrusive<metatomic_torch::SystemHolder>(
241→      this->atomic_types_, torch_positions, torch_cell, torch_pbc);
242→
243→  // 3. Compute and add neighbor lists to the system
244→  for (const auto &request : this->nl_requests_) {
245→    auto neighbors =
246→        this->computeNeighbors(request, nAtoms, positions, box, periodic);
247→    metatomic_torch::register_autograd_neighbors(system, neighbors,
248→                                                 this->check_consistency_);
249→    system->add_neighbor_list(request, neighbors);
250→  }
251→
252→  // 4. Execute the model
253→  metatensor_torch::TensorMap output_map;
254→  try {
255→    auto ivalue_output = this->model_.forward({
256→        std::vector<metatomic_torch::System>{system},
257→        evaluations_options_,
258→        this->check_consistency_,
259→    });
260→    auto dict_output = ivalue_output.toGenericDict();
261→    output_map = dict_output.at(this->energy_key_)
262→                     .toCustomClass<metatensor_torch::TensorMapHolder>();
263→
264→    // If we requested per-atom uncertainty and provided a positive threshold,
265→    // check the returned uncertainty values and log/warn if any atoms exceed
266→    // the threshold.
267→    if (this->uncertainty_threshold_ > 0) {
268→      try {
269→        // Check if the dict contains an uncertainty entry
270→        if (dict_output.contains(this->energy_uncertainty_key_)) {
271→          auto uncertainty_map =
272→              dict_output.at(this->energy_uncertainty_key_)
273→                  .toCustomClass<metatensor_torch::TensorMapHolder>();
274→          auto uncertainty_block =
275→              metatensor_torch::TensorMapHolder::block_by_id(uncertainty_map,
276→                                                             0);
277→
278→          // Expecting a per-atom tensor shaped [n_atoms, 1] (or similar)
279→          auto uncertainty_values = uncertainty_block->values();
280→          // Flatten to 1D of per-atom uncertainties
281→          auto flat_uncertainty =
282→              uncertainty_values.reshape({-1}).to(torch::kCPU);
283→          // If variance pointer provided, set it to the mean of per-atom
284→          // uncertainties
285→          if (variance != nullptr && flat_uncertainty.numel() > 0) {
286→            try {
287→              // TODO(rg): maybe allow the user to set the variance computation
288→              auto mean_unc = flat_uncertainty.to(torch::kFloat64).mean();
289→              *variance = mean_unc.item<double>();
290→            } catch (...) {
291→              // If mean computation fails, leave variance untouched.
292→              m_log->debug("[MetatomicPotential] Failed to compute mean "
293→                           "uncertainty for variance.");
294→            }
295→          }
296→
297→          // Compare with threshold
298→          auto atoms_above_threshold =
299→              flat_uncertainty > this->uncertainty_threshold_;
300→          if (torch::any(atoms_above_threshold).item<bool>()) {
301→            // Get the sample "atom" column and index it by the boolean mask
302→            // Samples holder utilities may vary; follow the typical metatensor
303→            // API
304→            auto samples = uncertainty_block->samples();
305→            // samples->column("atom") should return a tensor with atom indices
306→            auto atom_indices_all = samples->column("atom").to(torch::kCPU);
307→            auto atom_indices_above =
308→                atom_indices_all.index({atoms_above_threshold});
309→
310→            // Build a short human-readable list of offending atom indices
311→            std::ostringstream ss;
312→            ss << "atoms at index [";
313→            auto n_report = std::min<int64_t>(10, atom_indices_above.size(0));
314→            for (int64_t i = 0; i < n_report; ++i) {
315→              if (i > 0)
316→                ss << ", ";
317→              ss << atom_indices_above[i].item<int32_t>();
318→            }
319→            ss << "]";
320→            if (atom_indices_above.size(0) > n_report) {
321→              ss << " and " << (atom_indices_above.size(0) - n_report)
322→                 << " more";
323→            }
324→
325→            m_log->warn(
326→                "[MetatomicPotential] The uncertainty on atomic energies for "
327→                "{} "
328→                "are larger than the threshold of {}. (Key: {}) Be careful "
329→                "when analyzing "
330→                "the results, and consider retraining the model to better "
331→                "describe these configurations.",
332→                ss.str(), this->uncertainty_threshold_,
333→                this->energy_uncertainty_key_);
334→          }
335→        }
336→      } catch (const std::exception &e) {
337→        // Don't fail the run for uncertainty-check failures; log and continue.
338→        m_log->warn("[MetatomicPotential] Failed to check {}: {}",
339→                    this->energy_uncertainty_key_, e.what());
340→      }
341→    }
342→
343→  } catch (const std::exception &e) {
344→    m_log->error("[MetatomicPotential] Model evaluation failed: {}", e.what());
345→    throw;
346→  }
347→
348→  // 5. Extract energy and compute gradients (forces)
349→  auto energy_block =
350→      metatensor_torch::TensorMapHolder::block_by_id(output_map, 0);
351→  auto energy_tensor = energy_block->values(); // This should be a [1, 1] tensor
352→
353→  if (energy_tensor.sizes().vec() != std::vector<int64_t>{1, 1}) {
354→    throw std::runtime_error(
355→        "Model did not return a single scalar energy value.");
356→  }
357→
358→  // Set the energy value
359→  *energy = energy_tensor.item<double>();
360→
361→  // Compute gradients w.r.t positions
362→  energy_tensor.backward();
363→  auto positions_grad = system->positions().grad();
364→
