  1→#include "../MatrixHelpers.hpp"
  2→#include "Matter.h"
  3→#include "catch2/catch_amalgamated.hpp"
  4→
  5→using namespace std::placeholders;
  6→using namespace Catch::Matchers;
  7→
  8→namespace tests {
  9→
 10→class PotTest {
 11→public:
 12→  PotTest()
 13→      : params{},
 14→        m1{nullptr},
 15→        pot_default{nullptr},
 16→        threshold{1e-2} {}
 17→
 18→  ~PotTest() {}
 19→
 20→  void SetUp() {
 21→    pot_default = helper_functions::makePotential(PotType::LJ, params);
 22→    m1 = std::make_shared<Matter>(pot_default, params);
 23→    std::string confile("pos.con");
 24→    m1->con2matter(confile);
 25→  }
 26→
 27→  void TearDown() {}
 28→
 29→protected:
 30→  Parameters params;
 31→  std::shared_ptr<Matter> m1;
 32→  std::shared_ptr<Potential> pot_default;
 33→  double threshold;
 34→};
 35→
 36→TEST_CASE_METHOD(PotTest, "Metatomic", "[PotTest]") {
 37→  SetUp();
 38→  auto matEq =
 39→      std::bind(helper_functions::eigenEquality<AtomMatrix>, _1, _2, threshold);
 40→  double expected_energy = 98374.87753058573;
 41→  AtomMatrix expected_forces(m1->numberOfAtoms(), 3);
 42→  expected_forces << -90017.67874663, 14048.6323898, 42667.56998833,
 43→      51715.62564964, 81020.09231365, -33288.72879168, 13893.5617694,
 44→      89793.76258628, 33937.11367155, -71755.76235155, 52324.79462503,
 45→      -32402.45955531, 46268.61994191, -89837.93451292, 11509.42733453,
 46→      -67770.6981497, -6678.90441423, -33619.79643378, -17329.67691782,
 47→      -68054.08864133, -59929.39232182, -14176.97088206, 30833.36510504,
 48→      -85864.44933633, -75239.50566824, -57104.7492775, -3715.98865599,
 49→      90169.5778592, 5214.90295971, 30786.57650636, 20281.84422414,
 50→      21840.57389606, 85752.46910389, 104913.11853287, -11120.68664665,
 51→      -29664.02315515, 9047.94473885, -62279.76038293, 73831.6816454;
 52→
 53→  double e_mta{0};
 54→  AtomMatrix f_mta = Eigen::MatrixXd::Ones(m1->numberOfAtoms(), 3);
 55→  params.potential_options.potential = PotType::METATOMIC;
 56→  params.metatomic_options.model_path = "lennard-jones.pt";
 57→  auto pot = helper_functions::makePotential(params.potential_options.potential,
 58→                                             params);
 59→  pot->force(m1->numberOfAtoms(), m1->getPositions().data(),
 60→             m1->getAtomicNrs().data(), f_mta.data(), &e_mta, nullptr,
 61→             m1->getCell().data());
 62→  REQUIRE_THAT(e_mta, WithinAbs(expected_energy, threshold));
 63→  REQUIRE(matEq(f_mta, expected_forces));
 64→  TearDown();
 65→}
 66→
 67→TEST_CASE_METHOD(PotTest,
 68→                 "Metatomic uncertainty populates variance (if available)",
 69→                 "[PotTest][uncertainty]") {
 70→  SetUp();
 71→
 72→  // Request uncertainty checking by setting a positive threshold.
 73→  // If the model does not provide per-atom energy_uncertainty, the variance
 74→  // should remain untouched (we initialize it to a sentinel and only assert
 75→  // when it changes).
 76→  params.potential_options.potential = PotType::METATOMIC;
 77→  params.metatomic_options.model_path = "lennard-jones.pt";
 78→  // request uncertainty checks
 79→  params.metatomic_options.uncertainty_threshold = 0.1;
 80→
 81→  auto pot = helper_functions::makePotential(params.potential_options.potential,
 82→                                             params);
 83→
 84→  double e_mta{0};
 85→  AtomMatrix f_mta = Eigen::MatrixXd::Zero(m1->numberOfAtoms(), 3);
 86→  double variance = -12345.6789; // sentinel
 87→
 88→  pot->force(m1->numberOfAtoms(), m1->getPositions().data(),
 89→             m1->getAtomicNrs().data(), f_mta.data(), &e_mta, &variance,
 90→             m1->getCell().data());
 91→
 92→  // If the model returned per-atom uncertainties, we expect variance to be
 93→  // set to their mean (>= 0 and finite). If not, variance remains the sentinel.
 94→  if (variance != -12345.6789) {
 95→    REQUIRE(std::isfinite(variance));
 96→    REQUIRE(variance >= 0.0);
 97→  }
 98→
 99→  TearDown();
100→}
