169→      }
170→    } catch (...) {
171→      // If introspection fails, we skip requesting uncertainty
172→      m_log->debug("[MetatomicPotential] Could not determine "
173→                   "'{}' per-atom capability; skipping.",
174→                   this->energy_uncertainty_key_);
175→    }
176→  }
177→
178→  this->check_consistency_ = m_params.metatomic_options.check_consistency;
179→  m_log->info("[MetatomicPotential] Initialization complete.");
180→}
