190→      torch::TensorOptions().dtype(torch::kFloat64).device(torch::kCPU);
191→
192→  auto torch_positions = torch::from_blob(const_cast<double *>(positions),
193→                                          {nAtoms, 3}, f64_options)
194→                             .to(this->dtype_)
195→                             .to(this->device_)
196→                             .set_requires_grad(true);
197→
198→  auto torch_cell =
199→      torch::from_blob(const_cast<double *>(box), {3, 3}, f64_options)
200→          .to(this->dtype_)
201→          .to(this->device_);
202→
203→  auto cell_norms = torch::norm(torch_cell, 2, /*dim=*/1);
204→  auto torch_pbc = cell_norms.abs() > 1e-9;
205→  bool periodic = torch::all(torch_pbc).item<bool>();
206→
207→  bool types_changed = false;
208→  if (static_cast<size_t>(nAtoms) != last_atomic_nrs_.size()) {
209→    types_changed = true;
210→  } else if (nAtoms > 0 && std::memcmp(atomicNrs, last_atomic_nrs_.data(),
211→                                       nAtoms * sizeof(int)) != 0) {
212→    types_changed = true;
213→  }
214→
215→  if (types_changed) {
216→    m_log->trace("[MetatomicPotential] Atomic numbers changed, re-creating "
217→                 "types tensor.");
218→    if (!atomicNrs) {
219→      throw std::runtime_error(
220→          "[MetatomicPotential] `atomicNrs` must be provided.");
221→    }
222→    std::vector<int32_t> types_vec(atomicNrs, atomicNrs + nAtoms);
223→    // XXX(rg): Reordering of labels might take place for non-conservative
224→    // forces / per atom energies
225→    this->atomic_types_ =
226→        torch::tensor(types_vec, torch::TensorOptions().dtype(torch::kInt32))
227→            .to(this->device_);
228→
229→    // Update the cache
230→    last_atomic_nrs_.assign(atomicNrs, atomicNrs + nAtoms);
231→  }
232→
233→  // 2. Create the metatomic::System object
234→  auto system = torch::make_intrusive<metatomic_torch::SystemHolder>(
235→      this->atomic_types_, torch_positions, torch_cell, torch_pbc);
236→
237→  // 3. Compute and add neighbor lists to the system
238→  for (const auto &request : this->nl_requests_) {
239→    auto neighbors =
240→        this->computeNeighbors(request, nAtoms, positions, box, periodic);
241→    metatomic_torch::register_autograd_neighbors(system, neighbors,
242→                                                 this->check_consistency_);
243→    system->add_neighbor_list(request, neighbors);
244→  }
245→
246→  // 4. Execute the model
247→  metatensor_torch::TensorMap output_map;
248→  try {
249→    auto ivalue_output = this->model_.forward({
250→        std::vector<metatomic_torch::System>{system},
251→        evaluations_options_,
252→        this->check_consistency_,
253→    });
254→    auto dict_output = ivalue_output.toGenericDict();
255→    output_map = dict_output.at(this->energy_key_)
256→                     .toCustomClass<metatensor_torch::TensorMapHolder>();
257→
258→    // If we requested per-atom uncertainty and provided a positive threshold,
259→    // check the returned uncertainty values and log/warn if any atoms exceed
260→    // the threshold.
261→    if (this->uncertainty_threshold_ > 0) {
262→      try {
263→        // Check if the dict contains an uncertainty entry
264→        if (dict_output.contains(this->energy_uncertainty_key_)) {
265→          auto uncertainty_map =
266→              dict_output.at(this->energy_uncertainty_key_)
267→                  .toCustomClass<metatensor_torch::TensorMapHolder>();
268→          auto uncertainty_block =
269→              metatensor_torch::TensorMapHolder::block_by_id(uncertainty_map,
270→                                                             0);
271→
272→          // Expecting a per-atom tensor shaped [n_atoms, 1] (or similar)
273→          auto uncertainty_values = uncertainty_block->values();
274→          // Flatten to 1D of per-atom uncertainties
275→          auto flat_uncertainty =
276→              uncertainty_values.reshape({-1}).to(torch::kCPU);
277→          // If variance pointer provided, set it to the mean of per-atom
278→          // uncertainties
279→          if (variance != nullptr && flat_uncertainty.numel() > 0) {
280→            try {
281→              // TODO(rg): maybe allow the user to set the variance computation
282→              auto mean_unc = flat_uncertainty.to(torch::kFloat64).mean();
283→              *variance = mean_unc.item<double>();
284→            } catch (...) {
285→              // If mean computation fails, leave variance untouched.
286→              m_log->debug("[MetatomicPotential] Failed to compute mean "
287→                           "uncertainty for variance.");
288→            }
289→          }
290→
291→          // Compare with threshold
292→          auto atoms_above_threshold =
293→              flat_uncertainty > this->uncertainty_threshold_;
294→          if (torch::any(atoms_above_threshold).item<bool>()) {
295→            // Get the sample "atom" column and index it by the boolean mask
296→            // Samples holder utilities may vary; follow the typical metatensor
297→            // API
298→            auto samples = uncertainty_block->samples();
299→            // samples->column("atom") should return a tensor with atom indices
300→            auto atom_indices_all = samples->column("atom").to(torch::kCPU);
301→            auto atom_indices_above =
302→                atom_indices_all.index({atoms_above_threshold});
303→
304→            // Build a short human-readable list of offending atom indices
305→            std::ostringstream ss;
306→            ss << "atoms at index [";
307→            auto n_report = std::min<int64_t>(10, atom_indices_above.size(0));
308→            for (int64_t i = 0; i < n_report; ++i) {
309→              if (i > 0)
310→                ss << ", ";
311→              ss << atom_indices_above[i].item<int32_t>();
312→            }
313→            ss << "]";
314→            if (atom_indices_above.size(0) > n_report) {
315→              ss << " and " << (atom_indices_above.size(0) - n_report)
316→                 << " more";
317→            }
318→
319→            m_log->warn(
320→                "[MetatomicPotential] The uncertainty on atomic energies for "
321→                "{} "
322→                "are larger than the threshold of {}. (Key: {}) Be careful "
323→                "when analyzing "
324→                "the results, and consider retraining the model to better "
325→                "describe these configurations.",
326→                ss.str(), this->uncertainty_threshold_,
327→                this->energy_uncertainty_key_);
328→          }
329→        }
330→      } catch (const std::exception &e) {
331→        // Don't fail the run for uncertainty-check failures; log and continue.
332→        m_log->warn("[MetatomicPotential] Failed to check {}: {}",
333→                    this->energy_uncertainty_key_, e.what());
334→      }
335→    }
336→
337→  } catch (const std::exception &e) {
338→    m_log->error("[MetatomicPotential] Model evaluation failed: {}", e.what());
339→    throw;
340→  }
341→
342→  // 5. Extract energy and compute gradients (forces)
343→  auto energy_block =
344→      metatensor_torch::TensorMapHolder::block_by_id(output_map, 0);
345→  auto energy_tensor = energy_block->values(); // This should be a [1, 1] tensor
346→
347→  if (energy_tensor.sizes().vec() != std::vector<int64_t>{1, 1}) {
348→    throw std::runtime_error(
349→        "Model did not return a single scalar energy value.");
350→  }
351→
352→  // Set the energy value
353→  *energy = energy_tensor.item<double>();
354→
355→  // Compute gradients w.r.t positions
356→  energy_tensor.backward();
357→  auto positions_grad = system->positions().grad();
358→
359→  // 6. Copy forces back to the output array
360→  // Forces are the negative gradient of the potential energy
361→  auto forces_tensor = -positions_grad.to(torch::kCPU).to(torch::kFloat64);
362→
363→  std::memcpy(forces, forces_tensor.contiguous().data_ptr<double>(),
364→              nAtoms * 3 * sizeof(double));
365→}
