367→// --- MetatomicPotential::computeNeighbors (helper) ---
368→
369→metatensor_torch::TensorBlock MetatomicPotential::computeNeighbors(
370→    metatomic_torch::NeighborListOptions request, long nAtoms,
371→    const double *positions, const double *box, bool periodic) {
372→
373→  auto cutoff = request->engine_cutoff(m_params.metatomic_options.length_unit);
374→
375→  VesinOptions options;
376→  options.cutoff = cutoff;
377→  options.full = request->full_list();
378→  options.return_shifts = true;
379→  options.return_distances = false; // we don't need distances
380→  options.return_vectors = true;    // metatomic uses vectors for autograd
381→
382→  VesinNeighborList *vesin_neighbor_list = new VesinNeighborList();
383→
384→  VesinDevice cpu{VesinCPU, 0};
385→  const char *error_message = nullptr;
386→  int status = vesin_neighbors(
387→      reinterpret_cast<const double (*)[3]>(positions),
388→      static_cast<size_t>(nAtoms), reinterpret_cast<const double (*)[3]>(box),
389→      &periodic, cpu, options, vesin_neighbor_list, &error_message);
390→
391→  if (status != EXIT_SUCCESS) {
392→    std::string err_str = "vesin_neighbors failed";
393→    delete vesin_neighbor_list;
394→    throw std::runtime_error(err_str);
395→  }
396→
397→  // Convert from vesin to metatomic format
398→  auto n_pairs = static_cast<int64_t>(vesin_neighbor_list->length);
399→  auto labels_options_cpu =
400→      torch::TensorOptions().dtype(torch::kInt32).device(torch::kCPU);
401→
402→  auto pair_samples_values = torch::empty({n_pairs, 5}, labels_options_cpu);
403→  auto pair_samples_values_ptr = pair_samples_values.accessor<int32_t, 2>();
404→  for (int64_t i = 0; i < n_pairs; i++) {
405→    pair_samples_values_ptr[i][0] =
406→        static_cast<int32_t>(vesin_neighbor_list->pairs[i][0]);
407→    pair_samples_values_ptr[i][1] =
408→        static_cast<int32_t>(vesin_neighbor_list->pairs[i][1]);
409→    pair_samples_values_ptr[i][2] = vesin_neighbor_list->shifts[i][0];
410→    pair_samples_values_ptr[i][3] = vesin_neighbor_list->shifts[i][1];
411→    pair_samples_values_ptr[i][4] = vesin_neighbor_list->shifts[i][2];
412→  }
413→
414→  // Custom deleter to free vesin's memory when the torch tensor is destroyed
415→  auto deleter = [=](void *) {
416→    vesin_free(vesin_neighbor_list);
417→    delete vesin_neighbor_list;
418→  };
419→
420→  auto pair_vectors = torch::from_blob(
421→      vesin_neighbor_list->vectors, {n_pairs, 3, 1}, deleter,
422→      torch::TensorOptions().dtype(torch::kFloat64).device(torch::kCPU));
423→
424→  auto neighbor_samples = torch::make_intrusive<metatensor_torch::LabelsHolder>(
425→      std::vector<std::string>{"first_atom", "second_atom", "cell_shift_a",
426→                               "cell_shift_b", "cell_shift_c"},
427→      pair_samples_values.to(this->device_));
428→
429→  auto labels_options_dev =
430→      torch::TensorOptions().dtype(torch::kInt32).device(this->device_);
431→  auto neighbor_component =
432→      torch::make_intrusive<metatensor_torch::LabelsHolder>(
433→          "xyz", torch::tensor({0, 1, 2}, labels_options_dev).reshape({3, 1}));
434→  auto neighbor_properties =
435→      torch::make_intrusive<metatensor_torch::LabelsHolder>(
436→          "distance", torch::zeros({1, 1}, labels_options_dev));
437→
438→  return torch::make_intrusive<metatensor_torch::TensorBlockHolder>(
439→      pair_vectors.to(this->dtype_).to(this->device_), neighbor_samples,
440→      std::vector<metatensor_torch::Labels>{neighbor_component},
441→      neighbor_properties);
442→}
